INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '2c9c4523-eb4f-4e2d-9aab-f0b4121b60b4',
  '00000000-0000-0000-0000-000000000001',
  $escape$SwiftUI Accessibility — VoiceOver, Dynamic Type, and Accessibility Modifiers$escape$,
  $escape$To ensure your SwiftUI app is accessible to users with disabilities, you must implement VoiceOver, Dynamic Type, and accessibility features. VoiceOver can be enabled by setting the `accessibility` modifier on views, such as a `Text` view. For example, to announce the text 'Hello World', you can use `Text("Hello World")`.accessibility(label: Text("Hello World"))`. Dynamic Type is enabled by setting the `font` property of a `Text` view with a `font` parameter of `.largeTitle()` or `.title3()`. To make a view focusable, you can use the `.focusable()` modifier. This will allow a user to navigate to the view using VoiceOver.$escape$,
  $escape$Text("Hello World")
    .accessibility(label: Text("Hello World"))
    .font(.largeTitle())$escape$,
  $escape$swift$escape$,
