INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '735d6eb1-3b3f-4a8c-a138-9189c6480554',
  '00000000-0000-0000-0000-000000000001',
  $escape$Swift - Dependency Management: Choosing Between SPM, CocoaPods, and Carthage$escape$,
  $escape$Swift Package Manager (SPM) is the built-in dependency manager for Swift projects. It's a simple, declarative way to specify dependencies. Create a `Package.swift` file to list your dependencies, and SPM will handle the installation. For example:

let package = Package(
    name: "MyApp",
    dependencies: [
        .package(url: "https://github.com/apple/swift-protobuf.git", from: "4.0.0")
    ],
    platforms: [
        .iOS(.v12),
        .macOS(.v10_15),
        .watchOS(.v5),
        .tvOS(.v13)
    ]
)

CocoaPods is a popular third-party dependency manager, but it's less seamless with SPM. Carthage is another third-party manager that's geared towards static frameworks.

When choosing a dependency manager, consider the type of project, the number of dependencies, and the level of complexity.$escape$,
  $escape$let package = Package(
    name: "MyApp",
    dependencies: [
        .package(url: "https://github.com/apple/swift-protobuf.git", from: "4.0.0")
    ],
    platforms: [
        .iOS(.v12),
        .macOS(.v10_15),
        .watchOS(.v5),
        .tvOS(.v13)
    ]
)$escape$,
  $escape$swift$escape$,
